   204→/// Run the launcher loop on the given filesystem and framebuffer.
   205→///
   206→/// Scans the root directory for `.PDB` files, renders the selection list,
   207→/// and blocks on button input until the user selects an app.
   208→///
   209→/// Returns the raw FAT 8.3 filename (`[u8; 11]`) of the chosen app.
   210→/// If no apps are found, blocks indefinitely on button input until one
   211→/// appears — in practice the caller should ensure the SD is populated.
   212→pub fn run_launcher<D: BlockDevice>(fs: &mut FsState<D>, buf: &mut FrameBuffer) -> [u8; 11]
   213→where
   214→    D::Error: core::fmt::Debug,
   215→{
   216→    run_launcher_with_refresh(fs, buf, |_| pd_display_refresh(0))
   217→}
   218→
   219→/// Run the launcher loop and invoke `refresh` after each redraw.
   220→pub fn run_launcher_with_refresh<D, F>(
   221→    fs: &mut FsState<D>,
   222→    buf: &mut FrameBuffer,
   223→    mut refresh: F,
   224→) -> [u8; 11]
   225→where
   226→    D: BlockDevice,
   227→    D::Error: core::fmt::Debug,
   228→    F: FnMut(&FrameBuffer),
   229→{
   230→    let mut apps = [AppInfo::default(); MAX_APPS];
   231→    let count = match fs.fs_opendir("") {
   232→        Ok(dir) => scan_apps(fs, dir, &mut apps).unwrap_or(0),
   233→        Err(_) => 0,
   234→    };
   235→    let mut state = LauncherState::new(count);
   236→
   237→    // Initial render — paint once before blocking on input.
   238→    render_launcher(buf, &apps[..count], &state);
   239→    refresh(buf);
   240→
   241→    loop {
   242→        let buttons = pd_input_wait_button();
   243→        let prev = state.selected;
   244→
   245→        if buttons & PD_BTN_DOWN != 0 {
   246→            state.move_down();
   247→        } else if buttons & PD_BTN_UP != 0 {
   248→            state.move_up();
   249→        } else if buttons & PD_BTN_OK != 0 && count > 0 {
   250→            let mut name = [0u8; 13];
   251→            let len = format_app_name(&apps[state.selected].filename, &mut name);
   252→            serial_write_bytes(b"APP:");
   253→            serial_write_bytes(&name[..len]);
   254→            serial_write_bytes(b"\n");
   255→            return apps[state.selected].filename;
   256→        }
   257→
   258→        // Re-render only when the selection actually moved.
   259→        if state.selected != prev {
   260→            render_launcher(buf, &apps[..count], &state);
   261→            refresh(buf);
   262→        }
   263→    }
   264→}
   265→
   266→/// Cursor state for the launcher selection list.
   267→pub struct LauncherState {
   268→    /// Total number of apps available.
   269→    pub count: usize,
   270→    /// Index of the currently highlighted app (0-based).
   271→    pub selected: usize,
   272→}
   273→
   274→impl LauncherState {
   275→    /// Create a new state for `count` apps; selection starts at 0.
   276→    pub fn new(count: usize) -> Self {
   277→        Self { count, selected: 0 }
   278→    }
   279→
   280→    /// Move selection up; wraps from 0 to `count - 1`.
   281→    pub fn move_up(&mut self) {
   282→        if self.count == 0 {
   283→            return;
   284→        }
   285→        self.selected = if self.selected == 0 {
   286→            self.count - 1
   287→        } else {
   288→            self.selected - 1
   289→        };
   290→    }
   291→
   292→    /// Move selection down; wraps from `count - 1` to 0.
   293→    pub fn move_down(&mut self) {
   294→        if self.count == 0 {
   295→            return;
   296→        }
   297→        self.selected = (self.selected + 1) % self.count;
   298→    }
   299→}
